import React from "react";
import { Box, Paper } from "@material-ui/core";

class Work extends React.Component {
  render() {
    return (
      <Box height="95vh" border={1} id="work">
        <Box height="100%">
        <Grid
            container
            spacing={3}
            style={{ height: "100%", padding: "1vh" }}
          >
          <Paper>sdf</Paper>
          </Grid>
        </Box>
      </Box>
    );
  }
}
export default Work;
